export default async function handler(req, res) {
  if (req.method !== "POST") {
    res.setHeader("Allow", "POST");
    return res.status(405).json({ error: "Method not allowed" });
  }

  const { amountCents, currency = "USD", planId = "small", senderName = "Someone special" } = req.body || {};
  const cents = Math.round(Number(amountCents || 0));
  if (!cents || cents < 1) {
    return res.status(400).json({ error: "Invalid amount" });
  }

  try {
    const token = await getAccessToken();
    const value = (cents / 100).toFixed(2);

    const createRes = await fetch(`${getBaseUrl()}/v2/checkout/orders`, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${token}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        intent: "CAPTURE",
        purchase_units: [
          {
            amount: {
              currency_code: String(currency).toUpperCase(),
              value,
            },
            description: `Petals and Words - ${planId === "small" ? "Small" : "Unlimited"} plan`,
            custom_id: `pw_${Date.now()}`,
          },
        ],
        payer: {
          name: {
            given_name: String(senderName || "Someone"),
          },
        },
      }),
    });

    const order = await createRes.json();
    if (!createRes.ok || !order?.id) {
      throw new Error(order?.message || "Unable to create PayPal order");
    }

    return res.status(200).json({
      orderId: order.id,
      status: order.status,
    });
  } catch (error) {
    console.error("PayPal create order failed:", error);
    return res.status(500).json({ error: "Unable to create PayPal order" });
  }
}

import process from "node:process";

async function createRazorpayOrder({ amountMinor, currency, receipt, notes }) {
  const keyId = process.env.RAZORPAY_KEY_ID;
  const keySecret = process.env.RAZORPAY_KEY_SECRET;

  if (!keyId || !keySecret) {
    throw new Error("Razorpay server credentials are missing");
  }

  const auth = Buffer.from(`${keyId}:${keySecret}`).toString("base64");
  const response = await fetch("https://api.razorpay.com/v1/orders", {
    method: "POST",
    headers: {
      Authorization: `Basic ${auth}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({
      amount: amountMinor,
      currency,
      receipt,
      notes,
    }),
  });

  const payload = await response.json();
  if (!response.ok) {
    throw new Error(payload?.error?.description || "Failed to create Razorpay order");
  }

  return payload;
}

export default async function handler(req, res) {
  if (req.method !== "POST") {
    res.setHeader("Allow", "POST");
    return res.status(405).json({ error: "Method not allowed" });
  }

  const { amountPaise, receipt, notes } = req.body || {};
  if (!amountPaise || Number(amountPaise) < 1) {
    return res.status(400).json({ error: "Invalid amount" });
  }

  try {
    const order = await createRazorpayOrder({
      amountMinor: Math.round(Number(amountPaise)),
      currency: "USD",
      receipt: receipt || `pw_${Date.now()}`,
      notes: notes || {},
    });
    return res.status(200).json({
      orderId: order.id,
      amount: order.amount,
      currency: order.currency,
    });
  } catch (error) {
    console.error("Razorpay order creation failed:", error);
    return res.status(500).json({ error: "Unable to create payment order" });
  }
}

